import{_ as e,o as t,c as a,i}from"./chunks/framework.DP1yFSuu.js";const k=JSON.parse('{"title":"Development Setup","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/development-setup.md","filePath":"contributing/development-setup.md"}'),n={name:"contributing/development-setup.md"};function p(o,s,l,d,h,r){return t(),a("div",null,[...s[0]||(s[0]=[i(`<h1 id="development-setup" tabindex="-1">Development Setup <a class="header-anchor" href="#development-setup" aria-label="Permalink to &quot;Development Setup&quot;">​</a></h1><p>This guide walks you through setting up a local development environment for the Cobalt monorepo.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Ensure the following tools are installed before proceeding:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Supported Version</th><th>Installation</th></tr></thead><tbody><tr><td>Node.js</td><td>20+</td><td><a href="https://nodejs.org" target="_blank" rel="noreferrer">nodejs.org</a> or use <code>nvm</code></td></tr><tr><td>pnpm</td><td>9+</td><td><code>corepack enable &amp;&amp; corepack prepare pnpm@latest --activate</code></td></tr><tr><td>Git</td><td>2.40+</td><td><a href="https://git-scm.com" target="_blank" rel="noreferrer">git-scm.com</a></td></tr></tbody></table><blockquote><p><strong>Tip:</strong> Node 20.x is the contributor baseline. The repository includes an <code>.nvmrc</code> file, so <code>nvm use</code> is the easiest way to match the expected environment.</p></blockquote><h2 id="clone-and-install" tabindex="-1">Clone and Install <a class="header-anchor" href="#clone-and-install" aria-label="Permalink to &quot;Clone and Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">git</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> clone</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> https://github.com/vizualization-lab/cobalt-design-system.git</span></span>
<span class="line"><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;">cd</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> cobalt-design-system</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> install</span></span></code></pre></div><p>The install step uses pnpm workspaces to link packages together. You should not need to install dependencies inside individual packages.</p><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><p>The repository is organized as a pnpm workspace:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span>cobalt-design-system/</span></span>
<span class="line"><span>├── packages/</span></span>
<span class="line"><span>│   ├── tokens/       # @cobalt/tokens — source tokens + generated outputs</span></span>
<span class="line"><span>│   ├── components/   # @cobalt/components — Lit web components</span></span>
<span class="line"><span>│   ├── react/        # @cobalt/react — React wrappers</span></span>
<span class="line"><span>│   ├── vue/          # @cobalt/vue — Vue wrappers</span></span>
<span class="line"><span>│   ├── angular/      # @cobalt/angular — Angular wrappers</span></span>
<span class="line"><span>│   ├── docs/         # @cobalt/docs — VitePress documentation site</span></span>
<span class="line"><span>│   ├── icons/        # @cobalt/icons — shared icon assets/runtime</span></span>
<span class="line"><span>│   └── workbench/    # isolated component preview environment</span></span>
<span class="line"><span>├── scripts/</span></span>
<span class="line"><span>├── pnpm-workspace.yaml</span></span>
<span class="line"><span>└── package.json</span></span></code></pre></div><p>Component source files live under <code>packages/components/src/components/</code>. Token source files live under <code>packages/tokens/tokens/</code>.</p><h2 id="environment-configuration" tabindex="-1">Environment Configuration <a class="header-anchor" href="#environment-configuration" aria-label="Permalink to &quot;Environment Configuration&quot;">​</a></h2><p>The docs site reads optional environment variables from a <code>.env</code> file at the repository root. This is useful when working from a fork or a different GitHub org.</p><p>To get started:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">cp</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> .env.example</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> .env</span></span></code></pre></div><p>Then uncomment and edit any values you need to override:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>COBALT_GITHUB_ORG</code></td><td>\`\`</td><td>GitHub organization name</td></tr><tr><td><code>COBALT_GITHUB_REPO</code></td><td><code>cobalt-design-system</code></td><td>GitHub repository name</td></tr><tr><td><code>COBALT_GITHUB_URL</code></td><td><code>https://github.com/{COBALT_GITHUB_ORG}/{COBALT_GITHUB_REPO}</code></td><td>Full GitHub repository URL</td></tr><tr><td><code>COBALT_REGISTRY_URL</code></td><td><code>https://registry.your-org.com</code></td><td>npm registry URL for docs examples</td></tr></tbody></table><p>If <code>COBALT_GITHUB_URL</code> is not set, it is derived automatically from <code>COBALT_GITHUB_ORG</code> and <code>COBALT_GITHUB_REPO</code>. The <code>.env</code> file is git-ignored.</p><h2 id="common-root-commands" tabindex="-1">Common Root Commands <a class="header-anchor" href="#common-root-commands" aria-label="Permalink to &quot;Common Root Commands&quot;">​</a></h2><p>Run these from the repository root:</p><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>pnpm build</code></td><td>Build every package in the workspace</td></tr><tr><td><code>pnpm dev</code></td><td>Start the docs site locally</td></tr><tr><td><code>pnpm workbench</code></td><td>Start the isolated component workbench</td></tr><tr><td><code>pnpm test</code></td><td>Run the workspace test suites</td></tr><tr><td><code>pnpm test:watch</code></td><td>Run the component test suite in watch mode</td></tr><tr><td><code>pnpm lint</code></td><td>Run ESLint across TypeScript source files</td></tr><tr><td><code>pnpm format</code></td><td>Format the repo with Prettier</td></tr><tr><td><code>pnpm clean</code></td><td>Remove build artifacts and docs cache</td></tr><tr><td><code>pnpm pack:local</code></td><td>Build local publish-style tarballs for external apps</td></tr></tbody></table><p>When you only need one package, prefer package-scoped commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> build</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> test</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/docs</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> build</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/docs</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> preview</span></span></code></pre></div><h2 id="component-workbench" tabindex="-1">Component Workbench <a class="header-anchor" href="#component-workbench" aria-label="Permalink to &quot;Component Workbench&quot;">​</a></h2><p>The workbench is a lightweight Vite-powered environment for developing and previewing components in isolation. It avoids much of the docs-site overhead while still giving you live component and token feedback.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> workbench</span></span></code></pre></div><p>Typical workbench use cases:</p><ul><li>iterate on component TS and generated styles quickly</li><li>preview token changes without navigating the full docs site</li><li>validate composed examples before writing docs</li></ul><h2 id="running-the-documentation-site" tabindex="-1">Running the Documentation Site <a class="header-anchor" href="#running-the-documentation-site" aria-label="Permalink to &quot;Running the Documentation Site&quot;">​</a></h2><p>The docs site is built with VitePress:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Start the local docs dev server</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Build the docs package</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/docs</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> build</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Preview the production build</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/docs</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> preview</span></span></code></pre></div><p><code>pnpm dev</code> is the default contributor entry point for docs work because it runs the same site most users consume.</p><h2 id="running-tests" tabindex="-1">Running Tests <a class="header-anchor" href="#running-tests" aria-label="Permalink to &quot;Running Tests&quot;">​</a></h2><p>Use the workspace or package-scoped commands depending on the change:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Run all workspace tests</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> test</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Run the component test suite directly</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --filter</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> test</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Re-run component tests in watch mode</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> test:watch</span></span></code></pre></div><p>Component tests run through Web Test Runner with Playwright-backed browsers. Accessibility audits are part of the component test suite, so there is no separate root-level <code>pnpm test:a11y</code> command today.</p><h2 id="local-testing-in-external-apps" tabindex="-1">Local Testing in External Apps <a class="header-anchor" href="#local-testing-in-external-apps" aria-label="Permalink to &quot;Local Testing in External Apps&quot;">​</a></h2><p>When developing Cobalt, you may need to validate changes in a separate application before publishing.</p><h3 id="using-pack-local-recommended" tabindex="-1">Using <code>pack:local</code> (recommended) <a class="header-anchor" href="#using-pack-local-recommended" aria-label="Permalink to &quot;Using \`pack:local\` (recommended)&quot;">​</a></h3><p><code>pnpm pack:local</code> builds publish-style tarballs. This is the safest option because it validates exports, file inclusion, and build output rather than relying on symlinks.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> pack:local</span></span></code></pre></div><p>Then install the generated tarballs in your app:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">npm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> install</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> /path/to/cobalt/local-packs/</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;">*</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;">.tgz</span></span></code></pre></div><p>If you already ran <code>pnpm build</code>, you can skip the extra build step:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> pack:local</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --skip-build</span></span></code></pre></div><h3 id="using-pnpm-link-faster-iteration" tabindex="-1">Using <code>pnpm link</code> (faster iteration) <a class="header-anchor" href="#using-pnpm-link-faster-iteration" aria-label="Permalink to &quot;Using \`pnpm link\` (faster iteration)&quot;">​</a></h3><p>If you need faster feedback and can tolerate symlink quirks:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;">cd</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> packages/components</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> link</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --global</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># in the external app</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> link</span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;"> --global</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components</span></span></code></pre></div><p>This avoids reinstalling tarballs after every change, but linked packages can surface duplicate dependency issues. If that happens, fall back to <code>pack:local</code>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Solution</th></tr></thead><tbody><tr><td><code>pnpm install</code> fails with workspace issues</td><td>Re-run from the repo root and confirm you are using pnpm 9+</td></tr><tr><td>Docs changes do not show up</td><td>Restart <code>pnpm dev</code> or run <code>pnpm clean</code> before restarting</td></tr><tr><td>Token changes do not appear in previews</td><td>Rebuild or refresh the workbench/docs site after the token package updates</td></tr><tr><td>Tests timeout in CI or locally</td><td>Run <code>pnpm exec playwright install</code> to install browser binaries</td></tr><tr><td>Linked packages behave strangely in an external app</td><td>Switch from <code>pnpm link</code> to <code>pnpm pack:local</code></td></tr></tbody></table><p>If you hit a problem that is not covered here, use the <a href="/cobalt-design-system/resources/contact.html">Contact</a> page or <a href="https://github.com/vizualization-lab/cobalt-design-system/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a>.</p>`,54)])])}const g=e(n,[["render",p]]);export{k as __pageData,g as default};
